import React, { useState } from 'react';
import { Link, useLocation } from 'react-router-dom';
import { Home, Book, Search, Bell, Menu, User } from './Icons';

interface LayoutProps {
  children: React.ReactNode;
}

const Layout: React.FC<LayoutProps> = ({ children }) => {
  const location = useLocation();
  const [sidebarOpen, setSidebarOpen] = useState(true);

  const isActive = (path: string) => {
    if (path === '/') return location.pathname === '/';
    return location.pathname.startsWith(path);
  };

  return (
    <div className="flex h-screen bg-gray-50 font-sans text-gray-900 overflow-hidden">
      {/* Sidebar */}
      <aside 
        className={`bg-white border-r border-gray-200 transition-all duration-500 ease-[cubic-bezier(0.4,0,0.2,1)] flex flex-col z-20 ${
          sidebarOpen ? 'w-64' : 'w-20'
        }`}
      >
        <div className="h-16 flex items-center px-6 border-b border-gray-100 overflow-hidden shrink-0">
            <div className={`font-bold text-xl text-absa-primary tracking-tight transition-opacity duration-300 ${!sidebarOpen ? 'opacity-0' : 'opacity-100'}`}>
             Absa <span className="text-gray-900 font-medium whitespace-nowrap">Marketplace</span>
            </div>
            <div className={`absolute font-bold text-xl text-absa-primary transition-opacity duration-300 pointer-events-none ${sidebarOpen ? 'opacity-0' : 'opacity-100'}`}>
             A
            </div>
        </div>

        <nav className="flex-1 py-6 px-3 space-y-2 overflow-y-auto hide-scrollbar">
          {[
            { to: '/', icon: Home, label: 'Home' },
            { to: '/catalog', icon: Book, label: 'Catalog' }
          ].map((item) => {
            const active = isActive(item.to);
            return (
              <Link 
                key={item.to}
                to={item.to} 
                className={`flex items-center px-3 py-2.5 rounded-lg transition-all duration-200 group relative active:scale-95 ${
                  active 
                    ? 'bg-absa-light text-absa-primary font-medium' 
                    : 'text-gray-600 hover:bg-gray-100 hover:text-gray-900'
                }`}
              >
                <item.icon size={20} className={`transition-colors duration-200 ${active ? 'text-absa-primary' : 'text-gray-500 group-hover:text-gray-700'}`} />
                {sidebarOpen && <span className="ml-3 transition-opacity duration-300">{item.label}</span>}

                {/* Active Dot Indicator */}
                <div className={`absolute right-3 w-1.5 h-1.5 rounded-full bg-absa-primary transition-all duration-300 transform ${active && sidebarOpen ? 'scale-100 opacity-100' : 'scale-0 opacity-0'}`} />
              </Link>
            );
          })}
        </nav>

        <div className="p-4 border-t border-gray-100">
           <button 
             onClick={() => setSidebarOpen(!sidebarOpen)}
             className="p-2 rounded-lg hover:bg-gray-100 text-gray-500 w-full flex justify-center transition-colors active:scale-90"
           >
             <Menu size={20} />
           </button>
        </div>
      </aside>

      {/* Main Content */}
      <div className="flex-1 flex flex-col overflow-hidden">
        {/* Header */}
        <header className="h-16 bg-white/80 backdrop-blur-md border-b border-gray-200 flex items-center justify-between px-8 sticky top-0 z-10">
          <div className="flex-1 max-w-2xl">
            <div className="relative group">
              <span className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                <Search size={16} className="text-gray-400 group-focus-within:text-absa-primary transition-colors" />
              </span>
              <input 
                type="text" 
                placeholder="Search for data assets, reports, or pipelines..." 
                className="w-full pl-10 pr-4 py-2 bg-gray-100 border-transparent text-gray-900 placeholder-gray-500 rounded-lg focus:outline-none focus:bg-white focus:ring-4 focus:ring-absa-primary/5 focus:border-absa-primary sm:text-sm transition-all duration-300"
              />
            </div>
          </div>

          <div className="flex items-center space-x-4 ml-4">
            <button className="p-2 rounded-full text-gray-500 hover:bg-gray-100 transition-all relative active:scale-90">
              <Bell size={20} className="hover:rotate-12 transition-transform" />
              <span className="absolute top-1.5 right-1.5 w-2.5 h-2.5 bg-absa-primary rounded-full border-2 border-white animate-pulse"></span>
            </button>
            <div className="h-8 w-8 rounded-full bg-gray-800 text-white flex items-center justify-center font-medium text-sm cursor-pointer hover:ring-2 hover:ring-offset-2 hover:ring-gray-800 transition-all active:scale-95">
              JD
            </div>
          </div>
        </header>

        {/* Page Content */}
        <main className="flex-1 overflow-auto p-8 scroll-smooth">
          <div className="max-w-7xl mx-auto animate-fade-in-up">
            {children}
          </div>
        </main>
      </div>
    </div>
  );
};

export default Layout;

import React from 'react';
import { Link } from 'react-router-dom';
import { Database, FileText, BarChart2, Grid, Clock } from './Icons';
import { Asset } from '../types';

interface AssetCardProps {
  asset: Asset;
  compact?: boolean;
}

const AssetCard: React.FC<AssetCardProps> = ({ asset, compact = false }) => {
  const getIcon = () => {
    switch(asset.type) {
      case 'Dataset': return <Database size={compact ? 18 : 20} />;
      case 'Report': return <FileText size={compact ? 18 : 20} />;
      case 'Model': return <BarChart2 size={compact ? 18 : 20} />;
      default: return <Grid size={compact ? 18 : 20} />;
    }
  };

  const getIconColor = () => {
    switch(asset.type) {
        case 'Dataset': return 'bg-blue-50 text-blue-600 group-hover:bg-blue-100';
        case 'Report': return 'bg-purple-50 text-purple-600 group-hover:bg-purple-100';
        case 'Model': return 'bg-orange-50 text-orange-600 group-hover:bg-orange-100';
        default: return 'bg-gray-50 text-gray-600 group-hover:bg-gray-100';
    }
  };

  return (
    <Link to={`/asset/${asset.id}`} className="block group h-full focus:outline-none focus:ring-2 focus:ring-absa-primary/40 rounded-xl">
      <div className="bg-white border border-gray-200 rounded-xl p-5 shadow-sm transition-all duration-300 ease-out h-full flex flex-col group-hover:-translate-y-1.5 group-hover:shadow-xl group-hover:shadow-gray-200/50 group-hover:border-absa-primary/20 group-active:scale-[0.98]">
        <div className="flex items-start justify-between mb-4">
          <div className="flex items-center space-x-3">
             <div className={`p-2.5 rounded-lg transition-all duration-300 ${getIconColor()}`}>
                 {getIcon()}
             </div>
             <div className="transition-transform duration-300 group-hover:translate-x-0.5">
                 <span className="text-xs font-semibold uppercase tracking-wider text-gray-500 block mb-0.5">{asset.type}</span>
                 {compact && <h3 className="font-semibold text-gray-900 line-clamp-1">{asset.title}</h3>}
             </div>
          </div>
          {asset.classification === 'Confidential' && (
             <span className="px-2 py-0.5 bg-red-50 text-red-700 text-[10px] font-bold uppercase tracking-wide rounded border border-red-100 transition-colors group-hover:bg-red-100">
                 Confidential
             </span>
          )}
        </div>

        {!compact && <h3 className="text-lg font-bold text-gray-900 mb-2 group-hover:text-absa-primary transition-colors duration-300">{asset.title}</h3>}

        <p className={`text-gray-600 text-sm mb-4 line-clamp-2 transition-colors duration-300 group-hover:text-gray-700 ${compact ? 'flex-1' : ''}`}>{asset.description}</p>

        {!compact && (
          <div className="flex flex-wrap gap-2 mb-4 mt-auto">
            {asset.tags.map(tag => (
              <span key={tag} className="px-2.5 py-1 bg-gray-100 text-gray-600 text-xs rounded-full font-medium transition-colors group-hover:bg-gray-200">
                {tag}
              </span>
            ))}
          </div>
        )}

        <div className={`flex items-center justify-between pt-4 border-t border-gray-50 mt-auto transition-colors duration-300 group-hover:border-gray-100 ${compact ? 'text-xs' : 'text-sm'}`}>
          <div className="flex flex-col">
            <span className="text-gray-500 text-xs">Owner</span>
            <span className="font-medium text-gray-700 group-hover:text-gray-900">{asset.owner}</span>
          </div>
          <div className="flex items-center text-gray-400 group-hover:text-gray-500">
             <span className="text-xs mr-1">{asset.updatedAt}</span>
             { !compact && <Clock size={14} className="group-hover:rotate-12 transition-transform" /> }
          </div>
        </div>
      </div>
    </Link>
  );
};

export default AssetCard;
